var kWeakestRows = function(mat, k) {
    const scores = mat.map((row, i) => [row.reduce((s, v) => s + v, 0), i]);
    scores.sort((a, b) => a[0] - b[0] || a[1] - b[1]);
    return scores.slice(0, k).map(x => x[1]);
};
